-- Knights cape catalog (500 rows from MSSQL KNIGHTS_CAPE)
-- C++ Reference: _KNIGHTS_CAPE struct, KnightsCapeSet.h
-- Columns map to C++ fields: sCapeIndex, nReqCoins, byGrade, nReqClanPoints, byRanking, Type, Ticket, BonusType

CREATE TABLE IF NOT EXISTS knights_cape (
    s_cape_index    SMALLINT    NOT NULL PRIMARY KEY,
    n_buy_price     INTEGER     NOT NULL DEFAULT 0,
    by_grade        SMALLINT    NOT NULL DEFAULT 3,
    n_buy_loyalty   INTEGER     NOT NULL DEFAULT 0,
    by_ranking      SMALLINT    NOT NULL DEFAULT 2,
    b_type          SMALLINT    NOT NULL DEFAULT 0,
    b_ticket        SMALLINT    NOT NULL DEFAULT 0,
    bonus_type      SMALLINT    NOT NULL DEFAULT 0
);

